mapper.select:
SELECT 
FROM collaboration_grant
WHERE ${directionColumn} = #{workspaceId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}

    AND status = #{status, typeHandler=com.pdp.persistence.typehandler.StringEnumTypeHandler}


    AND id > #{lastId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}

ORDER BY id ASC
LIMIT #{size}
